sql:
SELECT countries.name, historical_trends.trend_type
FROM countries
JOIN historical_trends ON countries.country_id = historical_trends.country_id;

SELECT AVG(population) AS average_population
FROM countries
WHERE region = 'Africa';

SELECT AVG(gdp) AS average_gdp
FROM countries
WHERE region = 'Asia';

SELECT c.name, (c.gdp / c.population) AS gdp_per_capita
FROM countries c
WHERE (c.gdp / c.population) = (
  SELECT MAX(c.gdp / c.population)
  FROM countries c
) OR (c.gdp / c.population) = (
  SELECT MIN(c.gdp / c.population)
  FROM countries c
);
